steps.content:
{
  "success": true,
  "data": "{
  "database": "ercot_db",
  "query": "WITH hourly_solar AS (\n  SELECT \n    DATE_TRUNC('hour', timestamp) AS hour,\n    AVG(generation_mw) AS solar_mw\n  FROM ercot_fuel_mix\n  WHERE fuel_category = 'solar'\n    AND timestamp >= '2021-01-01'\n    AND timestamp < '2025-01-01'\n  GROUP BY DATE_TRUNC('hour', timestamp)\n)\nSELECT \n  DATE_TRUNC('year', hs.hour) AS year,\n  COUNT(*) AS hours,\n  SUM(hs.solar_mw) AS total_solar_mwh,\n  SUM(hs.solar_mw * rt.lmp) / NULLIF(SUM(hs.solar_mw), 0) AS solar_weighted_avg_rt_lmp,\n  AVG(rt.lmp) AS simple_avg_rt_lmp\nFROM hourly_solar hs\nJOIN ercot_lmp rt \n  ON rt.zone_name = 'west' \n  AND rt.zone_type = 'hub' \n  AND rt.is_day_ahead = false\n  AND hs.hour = DATE_TRUNC('hour', rt.timestamp)\nWHERE hs.hour >= '2021-01-01' AND hs.hour < '2025-01-01'\nGROUP BY DATE_TRUNC('year', hs.hour)\nORDER BY year",
